import mathfrom build123d import *# Configurationn_flaps = 69pin_len = 3ph_cl = 0.4ph_sep = 1.2ph_rad = (ph_cl + pin_len) / 2ph_pitch = ph_sep + ph_rad * 2wh_rad_ph_cen = ph_pitch * n_flaps / (2 * math.pi)ph_wall_out = 2wh_rad_out = wh_rad_ph_cen + ph_rad + ph_wall_outwh_thickness = 3wh_rad_ph_in = wh_rad_ph_cen - ph_rad - 2.0spoke_wd = 6.0# Mount definitionswh_spacer_screw_diam = 3.0wh_spacer_hole_cl = 0.4wh_spacer_hole_diam = wh_spacer_screw_diam + wh_spacer_hole_clwh_spacer_hole_wall = 2.0with BuildPart() as wheel_blank:    Cylinder(radius=wh_rad_out, height=wh_thickness)    Hole(radius=2.5) # drive_shaft_diam / 2    with PolarLocations(radius=wh_rad_ph_cen, count=n_flaps):        Hole(radius=ph_rad)    # Radial Cutouts    with BuildSketch(Plane.XY) as cutter:        Circle(radius=wh_rad_ph_in)        Rectangle(wh_rad_ph_in * 2, wh_rad_ph_in * 2, rotation=45, mode=Mode.SUBTRACT)        Rectangle(wh_rad_ph_in * 2, spoke_wd, rotation=0, mode=Mode.ADD)        Rectangle(spoke_wd, wh_rad_ph_in * 2, rotation=0, mode=Mode.ADD)        Circle(radius=10.0, mode=Mode.ADD)    extrude(cutter.sketch, amount=-wh_thickness, mode=Mode.SUBTRACT)    # Screw Mounts    hole_pos_r = wh_rad_ph_in - wh_spacer_hole_wall - (wh_spacer_hole_diam / 2)    hole_pos_y = (spoke_wd / 2) + wh_spacer_hole_wall + (wh_spacer_hole_diam / 2)        with BuildSketch(Plane.XY) as mount:        with Locations((spoke_wd/2, spoke_wd/2)):            Rectangle(10, 10, align=(Align.MIN, Align.MIN))            Circle(10, mode=Mode.INTERSECT)            with Locations((hole_pos_y - (spoke_wd/2), hole_pos_r - (spoke_wd/2))):                Circle(wh_spacer_hole_diam / 2, mode=Mode.SUBTRACT)    extrude(mount.sketch, amount=wh_thickness, mode=Mode.ADD)export_step(wheel_blank.part, "wheel_v0.step")